// Connection pool management
let pool = flow.get('connectionPool') || {
    clients: ['pool-client-1', 'pool-client-2', 'pool-client-3'],
    currentIndex: 0,
    stats: {
        'pool-client-1': { requests: 0, errors: 0 },
        'pool-client-2': { requests: 0, errors: 0 },
        'pool-client-3': { requests: 0, errors: 0 }
    }
};

// Round-robin selection
let selectedClient = pool.clients[pool.currentIndex];
pool.currentIndex = (pool.currentIndex + 1) % pool.clients.length;

// Track usage
pool.stats[selectedClient].requests++;

// Set the selected client for the Modbus node
msg.server = selectedClient;
msg.poolStats = pool.stats;
msg.selectedClient = selectedClient;

flow.set('connectionPool', pool);
return msg;

// Circuit breaker implementation
let breaker = flow.get('circuitBreaker') || {
    state: 'CLOSED',
    failures: 0,
    successes: 0,
    lastFailureTime: 0,
    config: {
        failureThreshold: 5,
        successThreshold: 3,
        timeout: 30000 // 30 seconds
    }
};

let now = Date.now();

// State machine
switch (breaker.state) {
    case 'CLOSED':
        // Allow request to pass through
        msg.circuitState = 'CLOSED - Request allowed';
        break;

    case 'OPEN':
        // Check if timeout has passed
        if (now - breaker.lastFailureTime > breaker.config.timeout) {
            breaker.state = 'HALF_OPEN';
            breaker.successes = 0;
            msg.circuitState = 'HALF_OPEN - Testing recovery';
        } else {
            // Block request
            msg.circuitState = 'OPEN - Request blocked';
            msg.blocked = true;
            node.error('Circuit breaker OPEN', msg);
        }
        break;

    case 'HALF_OPEN':
        // Allow limited requests for testing
        msg.circuitState = 'HALF_OPEN - Test request';
        break;
}

flow.set('circuitBreaker', breaker);

if (!msg.blocked) {
    return msg;
}
return null;

// Update circuit breaker on success
let breaker = flow.get('circuitBreaker');

if (breaker) {
    breaker.failures = 0;

    if (breaker.state === 'HALF_OPEN') {
        breaker.successes++;
        if (breaker.successes >= breaker.config.successThreshold) {
            breaker.state = 'CLOSED';
            node.status({fill:'green', shape:'dot', text:'Circuit CLOSED'});
        }
    }

    flow.set('circuitBreaker', breaker);
}

msg.breakerState = breaker.state;
return msg;

// Update circuit breaker on failure
let breaker = flow.get('circuitBreaker');

if (breaker) {
    breaker.failures++;
    breaker.lastFailureTime = Date.now();

    if (breaker.failures >= breaker.config.failureThreshold) {
        breaker.state = 'OPEN';
        node.status({fill:'red', shape:'ring', text:'Circuit OPEN'});
    }

    if (breaker.state === 'HALF_OPEN') {
        breaker.state = 'OPEN';
        breaker.successes = 0;
    }

    flow.set('circuitBreaker', breaker);
}

msg.breakerState = breaker.state;
msg.error = 'Request failed';
return msg;

// Retry strategy implementation
let retry = msg.retry || {
    attempts: 0,
    maxAttempts: 5,
    strategy: 'exponential', // exponential, linear, fibonacci
    baseDelay: 1000,
    maxDelay: 30000
};

if (msg.error && retry.attempts < retry.maxAttempts) {
    retry.attempts++;

    // Calculate delay based on strategy
    let delay = retry.baseDelay;

    switch (retry.strategy) {
        case 'exponential':
            delay = Math.min(retry.baseDelay * Math.pow(2, retry.attempts - 1), retry.maxDelay);
            break;

        case 'linear':
            delay = retry.baseDelay;
            break;

        case 'fibonacci':
            let fib = [1, 1, 2, 3, 5, 8, 13, 21];
            let index = Math.min(retry.attempts - 1, fib.length - 1);
            delay = Math.min(retry.baseDelay * fib[index], retry.maxDelay);
            break;
    }

    // Add jitter (±10%)
    delay = delay * (0.9 + Math.random() * 0.2);

    msg.retry = retry;
    msg.retryDelay = Math.floor(delay);
    msg.retryInfo = `Attempt ${retry.attempts}/${retry.maxAttempts}, delay: ${msg.retryDelay}ms`;

    return [null, msg]; // Send to delay node
} else if (retry.attempts >= retry.maxAttempts) {
    msg.retryFailed = true;
    msg.retryInfo = `Max retries (${retry.maxAttempts}) exceeded`;
    return [msg, null]; // Send to dead letter queue
}

// First attempt
msg.retry = retry;
return [msg, null];

// Batch request aggregation
let batch = flow.get('requestBatch') || {
    requests: [],
    lastFlush: Date.now(),
    config: {
        maxSize: 10,
        maxWait: 100, // ms
        priority: ['HIGH', 'NORMAL', 'LOW']
    }
};

// Add request to batch
batch.requests.push({
    payload: msg.payload,
    priority: msg.priority || 'NORMAL',
    timestamp: Date.now()
});

// Check if batch should be flushed
let shouldFlush = false;
let flushReason = '';

if (batch.requests.length >= batch.config.maxSize) {
    shouldFlush = true;
    flushReason = 'Size limit reached';
} else if (Date.now() - batch.lastFlush > batch.config.maxWait) {
    shouldFlush = true;
    flushReason = 'Time window expired';
} else if (msg.priority === 'HIGH') {
    shouldFlush = true;
    flushReason = 'High priority request';
}

if (shouldFlush) {
    // Sort by priority
    batch.requests.sort((a, b) => {
        let priorityA = batch.config.priority.indexOf(a.priority);
        let priorityB = batch.config.priority.indexOf(b.priority);
        return priorityA - priorityB;
    });

    msg.batch = batch.requests;
    msg.batchSize = batch.requests.length;
    msg.flushReason = flushReason;

    // Reset batch
    batch.requests = [];
    batch.lastFlush = Date.now();
    flow.set('requestBatch', batch);

    return msg;
} else {
    // Wait for more requests
    flow.set('requestBatch', batch);
    msg.batched = true;
    msg.batchStatus = `Buffered (${batch.requests.length}/${batch.config.maxSize})`;
    node.status({fill:'yellow', shape:'dot', text:msg.batchStatus});
    return null;
}

// Process batched requests
msg.processedBatch = {
    size: msg.batchSize,
    reason: msg.flushReason,
    requests: msg.batch,
    timestamp: new Date().toISOString()
};

// Here you would typically convert the batch into
// appropriate Modbus requests

return msg;

// Collect metrics from all patterns
let metrics = flow.get('performanceMetrics') || {
    connectionPool: {},
    circuitBreaker: {},
    retryStats: {},
    batchStats: {},
    startTime: Date.now()
};

// Update metrics based on message source
if (msg.poolStats) {
    metrics.connectionPool = msg.poolStats;
}

if (msg.breakerState) {
    metrics.circuitBreaker.state = msg.breakerState;
    metrics.circuitBreaker.lastUpdate = Date.now();
}

if (msg.retryInfo) {
    metrics.retryStats.lastRetry = msg.retryInfo;
    metrics.retryStats.timestamp = Date.now();
}

if (msg.batchSize) {
    metrics.batchStats.lastBatchSize = msg.batchSize;
    metrics.batchStats.lastFlushReason = msg.flushReason;
}

// Calculate overall health score
let healthScore = 100;

if (metrics.circuitBreaker.state === 'OPEN') {
    healthScore -= 30;
} else if (metrics.circuitBreaker.state === 'HALF_OPEN') {
    healthScore -= 15;
}

metrics.healthScore = healthScore;
metrics.uptime = Math.floor((Date.now() - metrics.startTime) / 1000);

flow.set('performanceMetrics', metrics);
msg.metrics = metrics;

return msg;
